import httpx
import asyncio
from dataclasses import dataclass
from datetime import datetime, time as dtime
from typing import Optional
import redis.asyncio as redis

@dataclass
class PreFlightResult:
    passed: bool
    blocking_check: Optional[str]
    details: str

    def __bool__(self) -> bool:
        return self.passed


class PreFlightChecker:
    def __init__(
        self,
        gateway_url: str,
        pagerduty_token: str,
        jira_url: str,
        redis_url: str,
        peak_hours: tuple[int, int] = (9, 18),   # local hour range, exclusive
    ):
        self.gateway_url = gateway_url
        self.pagerduty_token = pagerduty_token
        self.jira_url = jira_url
        self.redis_url = redis_url
        self.peak_hours = peak_hours

    async def run(self, service: str, change_ticket_id: str) -> PreFlightResult:
        checks = [
            self._check_steady_state(),
            self._check_no_active_incident(service),
            self._check_not_peak_hours(),
            self._check_change_ticket(change_ticket_id),
            self._check_experiment_lock(service),
        ]
        for coro in checks:
            result = await coro
            if not result.passed:
                return result
        return PreFlightResult(passed=True, blocking_check=None, details="all checks passed")

    async def _check_steady_state(self) -> PreFlightResult:
        async with httpx.AsyncClient(timeout=5.0) as client:
            r = await client.get(f"{self.gateway_url}/metrics/current")
            data = r.json()
        error_rate = data["error_rate_pct"]
        p99 = data["p99_latency_ms"]
        p99_baseline = data["p99_baseline_ms"]
        if error_rate > 0.5:
            return PreFlightResult(False, "steady_state", f"error_rate={error_rate:.2f}% > 0.5%")
        if p99 > p99_baseline * 1.1:
            return PreFlightResult(False, "steady_state", f"p99={p99}ms > 110% of baseline {p99_baseline}ms")
        return PreFlightResult(True, None, "steady state ok")

    async def _check_no_active_incident(self, service: str) -> PreFlightResult:
        async with httpx.AsyncClient(timeout=5.0) as client:
            r = await client.get(
                "https://api.pagerduty.com/incidents",
                params={"statuses[]": ["triggered", "acknowledged"], "service_ids[]": [service]},
                headers={"Authorization": f"Token token={self.pagerduty_token}"},
            )
        incidents = r.json().get("incidents", [])
        if incidents:
            return PreFlightResult(False, "active_incident", f"{len(incidents)} active incident(s) in {service}")
        return PreFlightResult(True, None, "no active incidents")

    async def _check_not_peak_hours(self) -> PreFlightResult:
        now = datetime.now()
        start, end = self.peak_hours
        if now.weekday() < 5 and start <= now.hour < end:
            return PreFlightResult(
                False, "peak_hours",
                f"Current time {now.strftime('%H:%M')} is within peak hours {start}:00-{end}:00"
            )
        return PreFlightResult(True, None, "outside peak hours")

    async def _check_change_ticket(self, ticket_id: str) -> PreFlightResult:
        async with httpx.AsyncClient(timeout=5.0) as client:
            r = await client.get(
                f"{self.jira_url}/rest/api/3/issue/{ticket_id}",
                auth=("chaos-bot@company.com", "JIRA_API_TOKEN"),
            )
        status = r.json()["fields"]["status"]["name"]
        if status != "Approved":
            return PreFlightResult(False, "change_ticket", f"{ticket_id} status is '{status}', need 'Approved'")
        return PreFlightResult(True, None, f"{ticket_id} approved")

    async def _check_experiment_lock(self, service: str) -> PreFlightResult:
        r = redis.from_url(self.redis_url)
        lock_key = f"chaos:lock:{service}"
        acquired = await r.set(lock_key, "1", nx=True, ex=600)   # 10-min TTL
        await r.aclose()
        if not acquired:
            return PreFlightResult(False, "experiment_lock", f"Another experiment is running for {service}")
        return PreFlightResult(True, None, "lock acquired")
